#include <stdio.h>

int main() {
    unsigned char bitmap[32] = {0};

    // Set bit 2 in byte 4 (for character 34, which is '"')
    bitmap[4] |= 1 << 2;

    // Test the buggy macro
    #define CHAR_IN_CLASS_BUGGY(cls, chr)  \
      ((cls)[(chr) / 8] & 1 << ((chr) % 8))

    // Test the correct macro
    #define CHAR_IN_CLASS_CORRECT(cls, chr)  \
      ((cls)[(chr) / 8] & (1 << ((chr) % 8)))

    unsigned char chr = 34; // '"'

    printf("bitmap[4] = 0x%02x\n", bitmap[4]);
    printf("chr = %d\n", chr);
    printf("chr / 8 = %d\n", chr / 8);
    printf("chr %% 8 = %d\n", chr % 8);
    printf("1 << (chr %% 8) = 0x%02x\n", 1 << (chr % 8));

    printf("BUGGY: %d\n", CHAR_IN_CLASS_BUGGY(bitmap, chr));
    printf("CORRECT: %d\n", CHAR_IN_CLASS_CORRECT(bitmap, chr));

    return 0;
}
