#include <stdio.h>
#include <string.h>

#define CHAR_IN_CLASS(cls, chr)  \
  ((cls)[(chr) / 8] & 1 << ((chr) % 8))

int main() {
    unsigned char bitmap[32] = {0};

    // Set bit for 'x' (120)
    bitmap[120 / 8] |= 1 << (120 % 8);
    printf("bitmap[15] = 0x%02x\n", bitmap[15]);

    // Test with character 224 (0xE0)
    unsigned char chr = 224;
    int result = CHAR_IN_CLASS(bitmap, chr);
    printf("CHAR_IN_CLASS(bitmap, 224) = %d\n", result);
    printf("bitmap[28] = 0x%02x\n", bitmap[28]);
    printf("1 << (224 %% 8) = 0x%02x\n", 1 << (224 % 8));
    printf("bitmap[28] & (1 << (224 %% 8)) = 0x%02x\n", bitmap[28] & (1 << (224 % 8)));

    // Now test the negation
    int negated_result = !result;
    printf("!result = %d\n", negated_result);

    return 0;
}
